fun observeConnection(): Flow<ConnectionState> = callbackFlow {
    val listener = object : Listener {
        override fun onChanged(state: ConnectionState) {
            trySend(state)
        }
    }
    client.addListener(listener)
    awaitClose { client.removeListener(listener) }
}

viewLifecycleOwner.lifecycleScope.launch {
    viewLifecycleOwner.repeatOnLifecycle(Lifecycle.State.STARTED) {
        viewModel.uiState.collect { state ->
            render(state)
        }
    }
}

@Composable
fun FeedScreen(viewModel: FeedViewModel) {
    val state by viewModel.uiState.collectAsStateWithLifecycle()
    FeedContent(state)
}

class ChatViewModel(
    repository: ChatRepository
) : ViewModel() {
    val uiState = repository.observeConversation()
        .map(ChatUiState::Content)
        .catch { emit(ChatUiState.Error(it.toUserMessage())) }
        .stateIn(
            viewModelScope,
            SharingStarted.WhileSubscribed(5_000),
            ChatUiState.Loading
        )
}

